={{
  const SYSTEM_AUTHORS = ['ian', 'guesty cx', 'zendesk guesty', 'incident.io', 'system/unknown'];
  const comments = $json.comments || [];

  // 1. First try: find first real end-user (client)
  const clientComment = comments.find(c =>
    c.author_role === 'end-user' &&
    !SYSTEM_AUTHORS.includes((c.author_name || '').toLowerCase().trim())
  );
  if (clientComment) return clientComment.author_name;

  // 2. Fallback: first agent who is not a system author
  const agentComment = comments.find(c =>
    !SYSTEM_AUTHORS.includes((c.author_name || '').toLowerCase().trim())
  );
  return agentComment ? agentComment.author_name : 'Unknown';
}}

={{
  const NOISE_AUTHORS = ['ian', 'guesty cx', 'zendesk guesty', 'incident.io', 'system/unknown'];
  const comments = $json.comments || [];

  // Filter out noise, keep meaningful comments
  const meaningful = comments.filter(c =>
    !NOISE_AUTHORS.includes((c.author_name || '').toLowerCase().trim())
  );

  // Take last 15 to avoid token overflow
  const sliced = meaningful.slice(-15);

  return sliced.map(c =>
    c.author_name + ' (' + c.author_role + ', ' + c.created_at + '):\n' + c.body
  ).join('\n---\n');
}}
